output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT(YEAR(?foundYear) AS ?foundingYear) WHERE {
  wd:Q4833805 wdt:P571 ?foundYear
}

args.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT (YEAR(?foundingDate) AS ?year)
WHERE {
  wd:Q4833805 wdt:P571 ?foundingDate.
}
